-- YaCheck / MaCheck Thai FDA clinical draft import
-- Batch: thai_fda_20260718_v1
-- Generated: 2026-07-18
-- Safety: no DELETE/TRUNCATE/DROP; new rows are draft + active=false.
-- Existing published or in_review rows are not modified.

BEGIN;
SET LOCAL lock_timeout = '10s';
SET LOCAL statement_timeout = '120s';

DO $$
BEGIN
  IF to_regclass('public.medications') IS NULL OR to_regclass('public.drug_interactions') IS NULL THEN
    RAISE EXCEPTION 'Required clinical tables are missing';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_type t JOIN pg_enum e ON e.enumtypid = t.oid WHERE t.typname = 'clinical_record_status' AND e.enumlabel = 'draft') THEN
    RAISE EXCEPTION 'clinical_record_status.draft is missing';
  END IF;
END $$;

CREATE TEMP TABLE import_medications_thai_fda_20260718_v1 (
  code text PRIMARY KEY,
  name_en text NOT NULL,
  name_th text NOT NULL,
  category text NOT NULL,
  common_dosages_mg numeric[] NOT NULL,
  description_th text NOT NULL,
  active boolean NOT NULL CHECK (active = false),
  source_references text[] NOT NULL CHECK (cardinality(source_references) > 0),
  status public.clinical_record_status NOT NULL CHECK (status = 'draft'),
  review_notes text NOT NULL
) ON COMMIT DROP;


DO $$
BEGIN
  IF (SELECT count(*) FROM import_medications_thai_fda_20260718_v1) <> 279 THEN
    RAISE EXCEPTION 'Medication staging count must be 279';
  END IF;
  IF EXISTS (SELECT 1 FROM import_medications_thai_fda_20260718_v1 WHERE code !~ '^[a-z0-9]+(_[a-z0-9]+)*$') THEN
    RAISE EXCEPTION 'Invalid medication code format';
  END IF;
END $$;

SELECT code, name_en, name_th, category, common_dosages_mg, description_th, active, source_references, status, review_notes
FROM import_medications_thai_fda_20260718_v1
ON CONFLICT (code) DO UPDATE SET
  name_en = EXCLUDED.name_en,
  name_th = CASE WHEN EXCLUDED.name_th LIKE 'รอตรวจสอบ%' THEN public.medications.name_th ELSE EXCLUDED.name_th END,
  category = CASE WHEN EXCLUDED.category = 'รอตรวจสอบ' THEN public.medications.category ELSE EXCLUDED.category END,
  common_dosages_mg = CASE WHEN cardinality(EXCLUDED.common_dosages_mg) = 0 THEN public.medications.common_dosages_mg ELSE EXCLUDED.common_dosages_mg END,
  description_th = CASE WHEN EXCLUDED.description_th LIKE 'ข้อมูลฉบับร่าง%' THEN public.medications.description_th ELSE EXCLUDED.description_th END,
  active = false,
  source_references = (
    SELECT coalesce(array_agg(DISTINCT ref ORDER BY ref), ARRAY[]::text[])
    FROM unnest(coalesce(public.medications.source_references, ARRAY[]::text[]) || EXCLUDED.source_references) AS ref
    WHERE nullif(trim(ref), '') IS NOT NULL
  ),
  review_notes = CASE
    WHEN position('thai_fda_20260718_v1' in public.medications.review_notes) > 0 THEN public.medications.review_notes
    ELSE concat_ws(E'\n', nullif(public.medications.review_notes, ''), EXCLUDED.review_notes)
  END
WHERE public.medications.status = 'draft';

CREATE TEMP TABLE import_interactions_thai_fda_20260718_v1 (
  drug_1 text NOT NULL,
  drug_2 text NOT NULL,
  severity public.interaction_severity NOT NULL,
  title_th text NOT NULL,
  description_th text NOT NULL,
  advice_th text NOT NULL,
  status public.clinical_record_status NOT NULL CHECK (status = 'draft'),
  source_references text[] NOT NULL CHECK (cardinality(source_references) > 0),
  review_notes text NOT NULL,
  PRIMARY KEY (drug_1, drug_2),
  CHECK (drug_1 < drug_2)
) ON COMMIT DROP;


DO $$
BEGIN
  IF (SELECT count(*) FROM import_interactions_thai_fda_20260718_v1) <> 47 THEN
    RAISE EXCEPTION 'Interaction staging count must be 47';
  END IF;
  IF EXISTS (
    SELECT 1 FROM import_interactions_thai_fda_20260718_v1 i
    LEFT JOIN public.medications m1 ON m1.code = i.drug_1
    LEFT JOIN public.medications m2 ON m2.code = i.drug_2
    WHERE m1.code IS NULL OR m2.code IS NULL
  ) THEN
    RAISE EXCEPTION 'Interaction references a missing medication';
  END IF;
END $$;

SELECT drug_1, drug_2, severity, title_th, description_th, advice_th, status, source_references, review_notes
FROM import_interactions_thai_fda_20260718_v1
ON CONFLICT (drug_1, drug_2) DO UPDATE SET
  severity = CASE WHEN public.drug_interactions.severity = 'severe' OR EXCLUDED.severity = 'severe' THEN 'severe'::public.interaction_severity ELSE 'moderate'::public.interaction_severity END,
  title_th = CASE WHEN public.drug_interactions.severity = 'severe' OR EXCLUDED.severity = 'severe' THEN 'ห้ามรับประทานยาคู่นี้ร่วมกัน' ELSE 'โปรดสอบถามแพทย์หรือเภสัชกรก่อนใช้ร่วมกัน' END,
  description_th = CASE WHEN public.drug_interactions.severity = 'severe' OR EXCLUDED.severity = 'severe' THEN 'ตรวจพบว่ายาคู่นี้อยู่ในกลุ่มห้ามใช้ร่วมกัน ระบบไม่แสดงรายละเอียดผลกระทบเพื่อความปลอดภัย' ELSE 'ตรวจพบว่ายาคู่นี้ต้องได้รับการตรวจสอบก่อนใช้ร่วมกัน ระบบไม่แสดงรายละเอียดผลกระทบเพื่อความปลอดภัย' END,
  advice_th = CASE WHEN public.drug_interactions.severity = 'severe' OR EXCLUDED.severity = 'severe' THEN 'อย่าปรับหรือหยุดยาที่ใช้อยู่เอง ให้ติดต่อแพทย์หรือเภสัชกรทันที' ELSE 'อย่ารับประทานยาคู่นี้ร่วมกันจนกว่าจะได้รับคำแนะนำจากแพทย์หรือเภสัชกร' END,
  source_references = (
    SELECT coalesce(array_agg(DISTINCT ref ORDER BY ref), ARRAY[]::text[])
    FROM unnest(coalesce(public.drug_interactions.source_references, ARRAY[]::text[]) || EXCLUDED.source_references) AS ref
    WHERE nullif(trim(ref), '') IS NOT NULL
  ),
  review_notes = CASE
    WHEN position('thai_fda_20260718_v1' in public.drug_interactions.review_notes) > 0 THEN public.drug_interactions.review_notes
    ELSE concat_ws(E'\n', nullif(public.drug_interactions.review_notes, ''), EXCLUDED.review_notes)
  END
WHERE public.drug_interactions.status = 'draft';

DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM public.medications WHERE review_notes LIKE '%thai_fda_20260718_v1%' AND (status <> 'draft' OR active)) THEN
    RAISE EXCEPTION 'Imported medication escaped draft/inactive safety gate';
  END IF;
  IF EXISTS (SELECT 1 FROM public.drug_interactions WHERE review_notes LIKE '%thai_fda_20260718_v1%' AND status <> 'draft') THEN
    RAISE EXCEPTION 'Imported interaction escaped draft safety gate';
  END IF;
END $$;

SELECT
  (SELECT count(*) FROM public.medications WHERE review_notes LIKE '%thai_fda_20260718_v1%') AS batch_medications,
  (SELECT count(*) FROM public.drug_interactions WHERE review_notes LIKE '%thai_fda_20260718_v1%') AS batch_interactions,
  (SELECT count(*) FROM public.medications WHERE review_notes LIKE '%thai_fda_20260718_v1%' AND status = 'draft' AND NOT active) AS safe_draft_medications,
  (SELECT count(*) FROM public.drug_interactions WHERE review_notes LIKE '%thai_fda_20260718_v1%' AND status = 'draft') AS safe_draft_interactions;

-- Dry run safety gate: no database changes persist.
ROLLBACK;
